import React, { useRef, useState } from "react";
import { motion } from "framer-motion";
import clsx from "clsx";

export default function ProjectCard({ project, index }) {
  const [isHovered, setIsHovered] = useState(false);
  const ref = useRef(null);

  const containerVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, delay: index * 0.15 },
    },
  };

  return (
    <motion.div
      ref={ref}
      variants={containerVariants}
      className="relative group"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Card Container */}
      <motion.div
        className="bg-white dark:bg-zinc-800 rounded-xl overflow-hidden border border-zinc-200 dark:border-zinc-700 h-full flex flex-col"
        whileHover={{ y: -8 }}
        transition={{ type: "spring", stiffness: 400, damping: 10 }}
      >
        {/* Image Container */}
        <div className="relative h-48 md:h-56 bg-gradient-to-br from-zinc-100 to-zinc-200 dark:from-zinc-700 dark:to-zinc-600 overflow-hidden">
          {/* Placeholder gradient based on project color */}
          <motion.div
            className="absolute inset-0"
            style={{
              background: `linear-gradient(135deg, ${project.color}20 0%, ${project.color}05 100%)`,
            }}
            animate={isHovered ? { scale: 1.1 } : { scale: 1 }}
            transition={{ duration: 0.4 }}
          />

          {/* Project Icon/Badge */}
          <div className="absolute top-4 right-4 z-10">
            <motion.div
              className="w-12 h-12 rounded-lg flex items-center justify-center font-bold text-white"
              style={{ backgroundColor: project.color }}
              whileHover={{ rotate: 360 }}
              transition={{ duration: 0.6 }}
            >
              {project.id}
            </motion.div>
          </div>

          {/* Year Badge */}
          <div className="absolute top-4 left-4">
            <motion.span
              className="px-3 py-1 bg-white/90 dark:bg-zinc-900/90 backdrop-blur-sm rounded-full text-sm font-medium text-zinc-700 dark:text-zinc-300"
              animate={isHovered ? { scale: 1.05 } : {}}
            >
              {project.year}
            </motion.span>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 p-6 flex flex-col">
          {/* Title */}
          <h3 className="text-xl font-bold text-zinc-900 dark:text-white mb-2">
            {project.title}
          </h3>

          {/* Description */}
          <p className="text-zinc-600 dark:text-zinc-400 mb-4 flex-grow">
            {project.description}
          </p>

          {/* Tags */}
          <div className="flex flex-wrap gap-2 mb-4">
            {project.tags.slice(0, 3).map((tag, idx) => (
              <motion.span
                key={idx}
                className="px-3 py-1 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full text-xs font-medium"
                whileHover={{ scale: 1.05 }}
              >
                {tag}
              </motion.span>
            ))}
          </div>

          {/* Links */}
          <div className="flex gap-3 pt-4 border-t border-zinc-200 dark:border-zinc-700">
            <motion.a
              href={project.link}
              target="_blank"
              rel="noopener noreferrer"
              className="flex-1 px-4 py-2 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-lg font-medium text-center hover:shadow-lg hover:shadow-blue-500/30 transition-all"
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              Live Demo
            </motion.a>
            <motion.a
              href={project.github}
              target="_blank"
              rel="noopener noreferrer"
              className="flex-1 px-4 py-2 bg-zinc-100 dark:bg-zinc-700 text-zinc-900 dark:text-white rounded-lg font-medium text-center hover:bg-zinc-200 dark:hover:bg-zinc-600 transition-all"
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              GitHub
            </motion.a>
          </div>
        </div>
      </motion.div>

      {/* Glow effect on hover */}
      <motion.div
        className="absolute inset-0 rounded-xl pointer-events-none"
        style={{
          background: `radial-gradient(circle at center, ${project.color}15 0%, transparent 70%)`,
        }}
        animate={isHovered ? { opacity: 1 } : { opacity: 0 }}
        transition={{ duration: 0.3 }}
      />
    </motion.div>
  );
}
