import React from "react";
import { motion } from "framer-motion";
import SectionTitle from "../common/SectionTitle";
import { PORTFOLIO_DATA } from "@/utils/constants";

export default function About() {
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.15,
        delayChildren: 0.1,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" },
    },
  };

  return (
    <section
      id="about"
      className="relative py-20 md:py-32 bg-gradient-to-b from-transparent via-blue-50/30 to-transparent dark:via-blue-950/10 overflow-hidden"
    >
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Section Title */}
        <SectionTitle
          title="About Me"
          subtitle="My journey and approach to building digital products"
        />

        {/* Content Grid */}
        <motion.div
          className="grid grid-cols-1 md:grid-cols-2 gap-12 mt-16"
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: "-100px" }}
        >
          {/* Left Side - Story */}
          <motion.div className="space-y-6" variants={itemVariants}>
            {PORTFOLIO_DATA.aboutSections.map((section, index) => (
              <div key={index}>
                <h3 className="text-2xl font-bold text-zinc-900 dark:text-white mb-3">
                  {section.title}
                </h3>
                <p className="text-lg text-zinc-600 dark:text-zinc-400 leading-relaxed">
                  {section.content}
                </p>
              </div>
            ))}
          </motion.div>

          {/* Right Side - Experience Timeline */}
          <motion.div className="space-y-8" variants={itemVariants}>
            <h3 className="text-2xl font-bold text-zinc-900 dark:text-white mb-6">
              Experience
            </h3>
            {PORTFOLIO_DATA.experience.map((exp, index) => (
              <motion.div
                key={index}
                className="relative pl-6 border-l-2 border-blue-300 dark:border-blue-800 pb-8 last:pb-0"
                whileHover={{ x: 4 }}
                transition={{ type: "spring", stiffness: 400, damping: 10 }}
              >
                {/* Timeline Dot */}
                <motion.div
                  className="absolute -left-3 top-0 w-6 h-6 bg-blue-600 rounded-full border-4 border-white dark:border-zinc-900"
                  whileHover={{ scale: 1.3 }}
                />

                {/* Content */}
                <div>
                  <h4 className="font-bold text-lg text-zinc-900 dark:text-white">
                    {exp.role}
                  </h4>
                  <p className="text-blue-600 dark:text-blue-400 font-medium">
                    {exp.company}
                  </p>
                  <p className="text-sm text-zinc-500 dark:text-zinc-500 mb-2">
                    {exp.duration}
                  </p>
                  <p className="text-zinc-600 dark:text-zinc-400">
                    {exp.description}
                  </p>
                </div>
              </motion.div>
            ))}
          </motion.div>
        </motion.div>

        {/* Stats Section */}
        <motion.div
          className="grid grid-cols-1 md:grid-cols-4 gap-6 mt-20 pt-12 border-t border-zinc-200 dark:border-zinc-800"
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: "-50px" }}
        >
          {[
            { label: "Years Experience", value: "8+" },
            { label: "Projects Completed", value: "50+" },
            { label: "Happy Clients", value: "30+" },
            { label: "Technologies", value: "20+" },
          ].map((stat, index) => (
            <motion.div
              key={index}
              className="text-center"
              variants={itemVariants}
            >
              <motion.p
                className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-blue-500 bg-clip-text text-transparent mb-2"
                whileInView={{ y: [0, -10, 0] }}
                transition={{ duration: 0.8, repeat: Infinity }}
              >
                {stat.value}
              </motion.p>
              <p className="text-zinc-600 dark:text-zinc-400">{stat.label}</p>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
}
