import React from "react";
import { motion } from "framer-motion";

export default function SectionTitle({ title, subtitle, centered = true }) {
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
        delayChildren: 0.1,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.5 },
    },
  };

  return (
    <motion.div
      className={`mb-12 ${centered ? "text-center" : ""}`}
      variants={containerVariants}
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, margin: "-100px" }}
    >
      <motion.h2
        className="text-4xl md:text-5xl font-bold tracking-tight text-zinc-900 dark:text-white mb-4"
        variants={itemVariants}
      >
        {title}
      </motion.h2>
      {subtitle && (
        <motion.p
          className="text-lg text-zinc-600 dark:text-zinc-400 max-w-2xl mx-auto"
          variants={itemVariants}
        >
          {subtitle}
        </motion.p>
      )}
      <motion.div
        className={`h-1 bg-gradient-to-r from-blue-600 to-blue-500 rounded-full mt-6 ${
          centered ? "mx-auto" : ""
        }`}
        style={{ width: "80px" }}
        variants={itemVariants}
      />
    </motion.div>
  );
}
